checker_dsl:
EXISTS (`method call MC`, `expr E`) {
  OR {
    AND {
      (`MC is a method call`),
      (`MC's method is a PrintStackTraceMethod`),
      EXISTS (`argument A`) {
        AND {
          (`A is an argument of MC`),
          (`Data flow from A to a servlet writer sink exists via ServletWriterSourceToPrintStackTraceMethodFlow`)
        }
      },
      (`MC's qualifier is E`),
      NOT { (`E is a SuperAccess`) }
    },
    EXISTS (`method call STC`) {
      AND {
        (`STC is a method call`),
        EXISTS (`expr PW`) {
          EXISTS (`variable SWV`) {
            EXISTS (`method call PSC`) {
              AND {
                (`PW's type is java.io.PrintWriter and SWV's type is java.io.StringWriter`),
                OR {
                  AND {
                    (`PW is a ClassInstanceExpr`),
                    (`One argument of PW is an access of SWV`)
                  },
                  EXISTS (`variable access VA`) {
                    AND {
                      (`PW is a VarAccess to variable V`),
                      (`V has initializer I`),
                      (`printWriterOnStringWriter relationship holds between I and SWV`)
                    }
                  }
                },
                (`PSC is a method call and PSC's method is a PrintStackTraceMethod and One argument of PSC is PW and PSC's qualifier is E`),
                (`STC's qualifier is an access of SWV and STC's method is a ToStringMethod`)
              }
            }
          }
        },
        (`Data flow from STC expression node to MC expression node exists via StackTraceStringToHttpResponseSinkFlow`)
      }
    }
  }
}
